What does this program print?

```cpp
#include <iostream>
#include <vector>

int main()
{
    std::vector<int> v { 5, 10, 15, 20 };
    int len { static_cast<int>(v.size()) };
    int sum { 0 };
    for (int i = 0; i < len; ++i)
        sum += v[i];
    std::cout << sum / len << '\n';
}
```
